mapper.update:
UPDATE product
sku_name = #{skuName}, price = #{price}, stock = #{stock}, category_id = #{categoryId}, category_name = #{categoryName}, brand_id = #{brandId}, brand_name = #{brandName}, description = #{description}, status = #{status}, version = version + 1,
WHERE sku_id = #{skuId}
AND version = #{version}

UPDATE product
SET stock = stock - #{count}, version = version + 1
WHERE sku_id = #{skuId} AND stock >= #{count}

UPDATE product
SET stock = stock + #{count}, version = version + 1
WHERE sku_id = #{skuId}

update.foreach:
